using UnityEngine;

// Generic Singleton base class
public class Singleton<T> : MonoBehaviour where T : Component
{
    private static T instance;

    public static T Instance
    {
        get
        {
            if (instance == null)
            {
                instance = FindObjectOfType<T>();
                if (instance == null)
                {
                    GameObject obj = new GameObject();
                    obj.name = typeof(T).Name;
                    instance = obj.AddComponent<T>();
                }
            }
            return instance;
        }
    }

    protected virtual void Awake()
    {
        if (instance == null)
        {
            instance = this as T;
            DontDestroyOnLoad(gameObject);
        }
        else if (instance != this)
        {
            Destroy(gameObject);
        }
    }
}

// Game Manager — handles game state
public class GameManager : Singleton<GameManager>
{
    public int playerScore = 0;
    public int playerLives = 3;
    public bool isGamePaused = false;

    private void Start()
    {
        Debug.Log("GameManager initialized!");
    }

    public void AddScore(int points)
    {
        playerScore += points;
        Debug.Log("Score: " + playerScore);
    }

    public void LoseLife()
    {
        playerLives--;
        Debug.Log("Lives: " + playerLives);
        if (playerLives <= 0)
        {
            GameOver();
        }
    }

    private void GameOver()
    {
        Debug.Log("GAME OVER! Final Score: " + playerScore);
    }
}

// Audio Manager — handles sound
public class AudioManager : Singleton<AudioManager>
{
    public float masterVolume = 1f;
    public float sfxVolume = 1f;
    public float musicVolume = 0.8f;

    public void PlaySound(string soundName)
    {
        Debug.Log("Playing sound: " + soundName + " (Volume: " + sfxVolume * masterVolume + ")");
    }

    public void PlayMusic(string musicName)
    {
        Debug.Log("Playing music: " + musicName + " (Volume: " + musicVolume * masterVolume + ")");
    }
}

// Level Manager — handles level loading
public class LevelManager : Singleton<LevelManager>
{
    public int currentLevel = 1;
    public int maxLevel = 10;

    public void LoadLevel(int levelIndex)
    {
        if (levelIndex >= 1 && levelIndex <= maxLevel)
        {
            currentLevel = levelIndex;
            Debug.Log("Loading level: " + currentLevel);
            // UnityEngine.SceneManagement.SceneManager.LoadScene("Level" + currentLevel);
        }
        else
        {
            Debug.Log("Invalid level!");
        }
    }

    public void NextLevel()
    {
        if (currentLevel < maxLevel)
        {
            LoadLevel(currentLevel + 1);
        }
        else
        {
            Debug.Log("You've completed all levels!");
        }
    }
}

public class SingletonExample : MonoBehaviour
{
    void Start()
    {
        // Accessing singletons from anywhere
        GameManager.Instance.AddScore(100);
        GameManager.Instance.LoseLife();

        AudioManager.Instance.PlaySound("Coin");
        AudioManager.Instance.PlayMusic("Background");

        LevelManager.Instance.LoadLevel(3);
        LevelManager.Instance.NextLevel();

        // They persist across scenes
        Debug.Log("Score: " + GameManager.Instance.playerScore);
        Debug.Log("Current Level: " + LevelManager.Instance.currentLevel);
    }
}

